using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _evaluationMetrics;
    private readonly string[] _classLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Extract class labels before training
        var labelColumn = dataView.GetColumn<string>("Category").Distinct().OrderBy(l => l).ToArray();
        _classLabels = labelColumn;

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate on the full dataset for evaluation
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);

        _evaluationMetrics = BuildMetrics(cvResults);

        // Train final model on all data
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_classLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationMetrics GetMetrics() => _evaluationMetrics;

    private EvaluationMetrics BuildMetrics(
        IReadOnlyList<TrainCatalogBase.CrossValidationResult<Microsoft.ML.Data.MulticlassClassificationMetrics>> cvResults)
    {
        var avgMetrics = new EvaluationMetrics
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
        };

        // Build per-class metrics from the last fold's confusion matrix
        var lastMetrics = cvResults.Last().Metrics;
        var perClass = new List<PerClassMetrics>();
        for (int i = 0; i < lastMetrics.PerClassPrecision.Count && i < _classLabels.Length; i++)
        {
            perClass.Add(new PerClassMetrics
            {
                Class = _classLabels[i],
                Precision = lastMetrics.PerClassPrecision[i],
                Recall = lastMetrics.PerClassRecall[i],
                F1Score = 2 * (lastMetrics.PerClassPrecision[i] * lastMetrics.PerClassRecall[i])
                    / (lastMetrics.PerClassPrecision[i] + lastMetrics.PerClassRecall[i] + 1e-10)
            });
        }
        avgMetrics.PerClassMetrics = perClass.ToArray();

        return avgMetrics;
    }
}

