var perClass = new List<PerClassMetrics>();
for (int i = 0; i < cm.PerClassPrecision.Count && i < _classLabels.Length; i++)
{
    var precision = cm.PerClassPrecision[i];
    var recall = cm.PerClassRecall[i];
    perClass.Add(new PerClassMetrics
    {
        Class = _classLabels[i],
        Precision = precision,
        Recall = recall,
        F1Score = 2 * (precision * recall) / (precision + recall + 1e-10)
    });
}

